  onMessage: (message: LiveServerMessage) => void;
  onError: (error: ErrorEvent) => void;
  onClose: (event: CloseEvent) => void;
}

export class GeminiLiveService {
  private ai: GoogleGenAI;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  private sessionPromise: Promise<any> | null = null;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  // --- Realtime Live API ---

  async connect(callbacks: GeminiCallbacks) {
    this.sessionPromise = this.ai.live.connect({
      model: GEMINI_MODEL,
      callbacks: {
        onopen: callbacks.onOpen,
        onmessage: callbacks.onMessage,
        onerror: callbacks.onError,
        onclose: callbacks.onClose,
      },
      config: {
        responseModalities: [Modality.AUDIO],
        inputAudioTranscription: {},
        systemInstruction: `You are an expert musical companion and guitar technician. 
        Your goal is to listen to the user playing guitar and provide feedback, identify chords, or jam along.
        Keep your responses concise, encouraging, and musically technical when appropriate.
        If the user plays something, try to identify the genre or the progression.`,
      },
    });
    return this.sessionPromise;
  }

  async sendAudioChunk(base64Data: string) {
    if (!this.sessionPromise) return;

    const session = await this.sessionPromise;
    session.sendRealtimeInput({
      media: {
        mimeType: 'audio/pcm;rate=16000',
        data: base64Data
      }
    });
  }

  async disconnect() {
    this.sessionPromise = null;
  }

  // --- Static File Analysis (New) ---

  async analyzeAudioFile(base64Data: string, mimeType: string, config: AnalysisConfig): Promise<MidiAnalysisResult> {
    const prompt = `
      Analyze this audio file carefully to create a MIDI representation.

      Configuration:
      - Mode: ${config.mode}
      - Polyphony: ${config.polyphony}
      - Primary Instrument: ${config.instrument || 'Auto-detect'}

      Tasks:
      1. Detect the Key Signature, Tempo, and Time Signature.
      2. Identify the instruments. If 'full_song' mode is active, separate distinct instruments into separate tracks.
      3. Transcribe the notes for each instrument/track accurately.

      Output strictly JSON fitting the schema provided.
    `;

    const response = await this.ai.models.generateContent({
      model: 'gemini-2.5-flash', // Using standard Flash for high capacity file analysis
      contents: {
        parts: [
          { inlineData: { mimeType, data: base64Data } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            keySignature: { type: Type.STRING, description: "Key of the song, e.g. C Major, F# Minor" },
            tempo: { type: Type.NUMBER, description: "BPM" },
            timeSignature: { type: Type.STRING, description: "e.g. 4/4" },
            tracks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING, description: "Instrument name" },
                  channel: { type: Type.INTEGER, description: "MIDI Channel 0-15. Use 9 for Drums." },
                  notes: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        midi: { type: Type.INTEGER, description: "MIDI note number 0-127" },
                        startTime: { type: Type.NUMBER, description: "Start time in seconds" },
                        duration: { type: Type.NUMBER, description: "Duration in seconds" },
                        velocity: { type: Type.INTEGER, description: "Velocity 0-127" }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as MidiAnalysisResult;
    }
    throw new Error("No analysis data returned");
  }
}

export const geminiService = new GeminiLiveService();

import React, { useState, useRef } from 'react';
import { Upload, Music, Check, Loader2, Download, FileAudio, Settings } from 'lucide-react';
import { AnalysisConfig, MidiAnalysisResult } from '../types';
import { geminiService } from '../services/geminiService';
import { generateMidiFile } from '../services/midiGeneration';

const FileAnalyzer: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [config, setConfig] = useState<AnalysisConfig>({
    mode: 'single',
    polyphony: 'monophonic',
    instrument: 'Guitar'
  });
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<MidiAnalysisResult | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setResult(null);
    }
  };

  const handleAnalyze = async () => {
    if (!file) return;

    setIsAnalyzing(true);
    setResult(null);

    try {
      const reader = new FileReader();
      reader.onload = async () => {
        const base64String = (reader.result as string).split(',')[1];
        const analysis = await geminiService.analyzeAudioFile(
          base64String,
          file.type,
          config
        );
        setResult(analysis);
        setIsAnalyzing(false);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      alert("Analysis failed. Please try a shorter audio clip (< 2 mins).");
      setIsAnalyzing(false);
    }
  };

  const downloadMidi = () => {
    if (!result) return;
    const midiBytes = generateMidiFile(result);
    const blob = new Blob([midiBytes], { type: 'audio/midi' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `fretwiz_analysis_${Date.now()}.mid`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="flex flex-col h-full bg-zinc-900 rounded-2xl border border-zinc-800 overflow-hidden shadow-lg p-6 gap-6 relative">
      <div className="flex items-center gap-3 border-b border-zinc-800 pb-4">
