           {isAnalyzing && (
              <div className="absolute inset-0 flex flex-col items-center justify-center z-10 bg-zinc-950/80 backdrop-blur-sm">
                 <Loader2 className="w-10 h-10 text-purple-500 animate-spin mb-4" />
                 <p className="text-sm text-zinc-300 animate-pulse">Detecting key signature...</p>
                 <p className="text-xs text-zinc-500 mt-1">Transcribing notes...</p>
              </div>
           )}

           {result && (
             <div className="flex-1 flex flex-col animate-in fade-in zoom-in duration-300">
                <div className="grid grid-cols-2 gap-4 mb-6">
                   <div className="bg-zinc-900 rounded-lg p-3 border border-zinc-800">
                      <div className="text-xs text-zinc-500 uppercase">Key Signature</div>
                      <div className="text-2xl font-bold text-purple-400">{result.keySignature}</div>
